import React, { useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { getEventById } from '../../data/events';
import { sendBookingEmail } from '../../services/emailService';
import './Booking.css';

function Booking() {
  const { id } = useParams();
  const navigate = useNavigate();
  const event = getEventById(id);

  const [form, setForm] = useState({
    name: '',
    email: '',
    phone: '',
    tickets: 1,
    specialRequests: '',
  });

  const [status, setStatus] = useState('idle'); // idle | loading | success | error
  const [errorMsg, setErrorMsg] = useState('');

  if (!event) {
    return (
      <div className="container" style={{ padding: '80px 24px', textAlign: 'center' }}>
        <h2>Event not found</h2>
        <Link to="/events" className="btn-primary" style={{ marginTop: '20px' }}>Back to Events</Link>
      </div>
    );
  }

  const total = event.price * form.tickets;

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: name === 'tickets' ? parseInt(value) : value }));
  };

  const validate = () => {
    if (!form.name.trim()) return 'Please enter your full name.';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) return 'Please enter a valid email address.';
    if (!/^[6-9]\d{9}$/.test(form.phone)) return 'Please enter a valid 10-digit Indian mobile number.';
    if (form.tickets < 1 || form.tickets > 10) return 'Tickets must be between 1 and 10.';
    return null;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const validationError = validate();
    if (validationError) {
      setErrorMsg(validationError);
      return;
    }

    setStatus('loading');
    setErrorMsg('');

    try {
      await sendBookingEmail(form, event);
      setStatus('success');
      navigate('/booking-success', {
        state: { bookingData: form, eventData: event, total },
      });
    } catch (err) {
      console.error('Email send failed:', err);
      // For POC: still navigate to success (email service not configured yet)
      // In production, handle real failure here
      setStatus('success');
      navigate('/booking-success', {
        state: { bookingData: form, eventData: event, total },
      });
    }
  };

  const formattedDate = new Date(event.date).toLocaleDateString('en-IN', {
    weekday: 'short', year: 'numeric', month: 'short', day: 'numeric',
  });

  return (
    <div className="booking-page">
      <div className="page-hero">
        <h1>Book Your Seat</h1>
        <p>Fill in your details to confirm your booking</p>
      </div>

      <div className="container booking-page__body">
        {/* Form */}
        <div className="booking-page__form-wrap">
          <h2 className="booking-page__form-title">Your Details</h2>

          {errorMsg && (
            <div className="booking-page__alert booking-page__alert--error">{errorMsg}</div>
          )}

          <form onSubmit={handleSubmit} noValidate>
            <div className="form-group">
              <label htmlFor="name">Full Name *</label>
              <input
                type="text"
                id="name"
                name="name"
                placeholder="e.g. Rohan Verma"
                value={form.name}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-row">
              <div className="form-group">
                <label htmlFor="email">Email Address *</label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  placeholder="you@example.com"
                  value={form.email}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="form-group">
                <label htmlFor="phone">Mobile Number *</label>
                <input
                  type="tel"
                  id="phone"
                  name="phone"
                  placeholder="10-digit mobile number"
                  value={form.phone}
                  onChange={handleChange}
                  required
                />
              </div>
            </div>

            <div className="form-group">
              <label htmlFor="tickets">Number of Tickets *</label>
              <select id="tickets" name="tickets" value={form.tickets} onChange={handleChange}>
                {[...Array(Math.min(10, event.seatsLeft))].map((_, i) => (
                  <option key={i + 1} value={i + 1}>{i + 1} ticket{i > 0 ? 's' : ''}</option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label htmlFor="specialRequests">Special Requests (optional)</label>
              <textarea
                id="specialRequests"
                name="specialRequests"
                rows="3"
                placeholder="Dietary needs, accessibility, seating preferences..."
                value={form.specialRequests}
                onChange={handleChange}
              />
            </div>

            <div className="booking-page__total">
              <span>{form.tickets} ticket{form.tickets > 1 ? 's' : ''} × ₹{event.price.toLocaleString('en-IN')}</span>
              <span className="booking-page__total-amount">₹{total.toLocaleString('en-IN')}</span>
            </div>

            <p className="booking-page__email-note">
              📧 A confirmation email will be sent to <strong>{form.email || 'your email'}</strong> and our team will be notified.
            </p>

            <button
              type="submit"
              className="btn-primary booking-page__submit"
              disabled={status === 'loading'}
            >
              {status === 'loading' ? 'Processing...' : `Confirm Booking – ₹${total.toLocaleString('en-IN')}`}
            </button>
          </form>
        </div>

        {/* Summary */}
        <div className="booking-page__summary">
          <h3>Order Summary</h3>
          <img src={event.image} alt={event.title} className="booking-page__summary-img" />
          <div className="booking-page__summary-details">
            <h4>{event.title}</h4>
            <p>📅 {formattedDate} · {event.time}</p>
            <p>📍 {event.location}</p>
            <p>🎟️ {event.category}</p>
          </div>
          <div className="booking-page__summary-price">
            <span>Subtotal</span>
            <span>₹{(event.price * form.tickets).toLocaleString('en-IN')}</span>
          </div>
          <div className="booking-page__summary-price booking-page__summary-price--total">
            <span>Total</span>
            <span>₹{total.toLocaleString('en-IN')}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Booking;
